import { formatPKR } from '../utils/finance';
import './PortfolioSummary.css';

export default function PortfolioSummary({ stats }) {
  const { totalInvested, weightedReturn, riskDistribution, diversificationScore, isHighRiskWarning } = stats;

  return (
    <div className="portfolio-summary">
      {isHighRiskWarning && (
        <div className="ps-warning">
          ⚠️ Over 70% of your portfolio is in high-risk products. Consider diversifying.
        </div>
      )}

      <div className="ps-stats">
        <div className="ps-stat">
          <span className="ps-stat-label">Total Invested</span>
          <span className="ps-stat-val accent-blue">{formatPKR(totalInvested)}</span>
        </div>
        <div className="ps-stat">
          <span className="ps-stat-label">Weighted Return</span>
          <span className="ps-stat-val accent-green">+{weightedReturn}%</span>
        </div>
        <div className="ps-stat">
          <span className="ps-stat-label">Diversification</span>
          <span className="ps-stat-val">{diversificationScore}/100</span>
        </div>
      </div>

      <div className="ps-risk-section">
        <p className="ps-section-label">Risk Distribution</p>
        <div className="ps-risk-bars">
          {['low','medium','high'].map(r => (
            <div key={r} className="ps-risk-row">
              <span className={`ps-risk-label risk-${r}`}>
                {r.charAt(0).toUpperCase() + r.slice(1)}
              </span>
              <div className="ps-bar-track">
                <div
                  className={`ps-bar-fill bar-${r}`}
                  style={{ width: `${riskDistribution[r]}%` }}
                />
              </div>
              <span className="ps-risk-pct">{riskDistribution[r].toFixed(0)}%</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
